func (i *WpImageDescriptionV1) Dispatch(opcode uint32, fd int, data []byte) {
	switch opcode {
	case 0:
		if i.failedHandler == nil {
			return
		}
		var e WpImageDescriptionV1FailedEvent
		l := 0
		e.Cause = client.Uint32(data[l : l+4])
		l += 4
		msgLen := client.PaddedLen(int(client.Uint32(data[l : l+4])))
		l += 4
		e.Msg = client.String(data[l : l+msgLen])
		l += msgLen

		i.failedHandler(e)
	case 1:
		if i.readyHandler == nil {
			return
		}
		var e WpImageDescriptionV1ReadyEvent
		l := 0
		e.Identity = client.Uint32(data[l : l+4])
		l += 4

		i.readyHandler(e)
	case 2:
		if i.ready2Handler == nil {
			return
		}
		var e WpImageDescriptionV1Ready2Event
		l := 0
		e.IdentityHi = client.Uint32(data[l : l+4])
		l += 4
		e.IdentityLo = client.Uint32(data[l : l+4])
		l += 4

		i.ready2Handler(e)
	}
}

